import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ChangeDetectorRef, OnInit } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { GiftModel, AddGift } from '../../Models/Gift';
import { Router, NavigationEnd } from '@angular/router';
import { Observable, filter } from 'rxjs';
import { DataViewModule } from 'primeng/dataview';
import { TagModule } from 'primeng/tag';
import { SelectButtonModule } from 'primeng/selectbutton';
import { ButtonModule } from 'primeng/button';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { DialogModule } from 'primeng/dialog';
import { PaginatorModule } from 'primeng/paginator';
import { InputTextModule } from 'primeng/inputtext';
import { FileUploadModule } from 'primeng/fileupload';

import { GiftsService } from '../../Services/GiftsService';
import { CategoryService } from '../../Services/CategoryService';
import { DonorService } from '../../Services/DonorService';
import { AuthorService } from '../../Services/AutorService';
import { CartService } from '../../Services/CartService';
import { SalesService } from '../../Services/SaleService';
import { GiftsWithBuyers } from '../../Models/Sales';
import { Category } from '../../Models/Category';
import { DonorModel } from '../../Models/Donor';
import { GiftBuyersDetailComp } from '../gift-buyers-detail-comp/gift-buyers-detail-comp';
import { GiftDetailComp } from '../gift-detail-comp/gift-detail-comp';
import { jwtDecode } from 'jwt-decode';

@Component({
  selector: 'app-manager-gifts',
  imports: [    CommonModule,
    GiftDetailComp,
    GiftBuyersDetailComp,
    FileUploadModule,
    FormsModule,
    DataViewModule,
    SelectButtonModule,
    TagModule,
    ButtonModule,
    ProgressSpinnerModule,
    DialogModule,
    PaginatorModule,
    InputTextModule
],
  templateUrl: './manager-gifts.html',
  styleUrl: './manager-gifts.scss',
})
export class ManagerGifts implements OnInit {
  gifts$!: Observable<GiftModel[]>;
  donors$!: Observable<DonorModel[]>;
  categories$!: Observable<Category[]>;

  giftsWithBuyers: GiftsWithBuyers[] = [];

  displayAddDialog: boolean = false;
  displayEditDialog: boolean = false;
  displayBuyersDialog: boolean = false;

  selectedGiftForEdit: any = {};
  selectedGiftId!: number;
  selectedGiftName: string = '';

  isAdmin: boolean = false;
  isLoading: boolean = false;
  errorMessage: string = '';

  allGifts: GiftModel[] = [];
  allDonors: DonorModel[] = [];
  allCategories: Category[] = [];
  pagedGifts: GiftModel[] = [];

  first: number = 0;
  rows: number = 6;
  cartUserId: number | null = null;

  newGift: AddGift = {
    Name: '',
    Description: '',
    CategoryId: 1,
    TicketPrice: 10,
    Image: '',
    DonorId: 1,
  };
  constructor(
    private giftService: GiftsService,
    private donorService: DonorService,
    private authorService: AuthorService,
    private categoryService: CategoryService,
    private salesService: SalesService,
    private cartService: CartService,
    private router: Router,
    private cdr: ChangeDetectorRef
  ) {}

  ngOnInit() {
    this.checkAdminStatus();
    this.loadInitialData();

    this.router.events
      .pipe(filter(event => event instanceof NavigationEnd))
      .subscribe(() => {
        this.loadInitialData();
        this.checkAdminStatus();
      });
  }
  private checkAdminStatus() {
    this.isAdmin = this.authorService.isManager();
  }

  // === Load All Data ===
  private loadInitialData() {
    this.loadGifts();
    this.loadCategories();
    this.loadDonors();
  }

  private loadGifts() {
    this.gifts$ = this.giftService.getGifts();
    this.gifts$.subscribe({
      next: data => {
        this.allGifts = data;
        this.updatePage();
        this.cdr.detectChanges();
      },
      error: err => console.error('Error loading gifts', err),
    });
  }
  private loadCategories() {
    this.categories$ = this.categoryService.getCategories();
    this.categories$.subscribe({
      next: data => {
        this.allCategories = [{ id: 0, name: 'כל הקטגוריות' }, ...data];
        this.updatePage();
        this.cdr.detectChanges();
      },
      error: err => console.error('Error loading categories', err),
    });
  }

  private loadDonors() {
    this.donors$ = this.donorService.getDonors();
    this.donors$.subscribe({
      next: data => {
        this.allDonors = data;
        this.updatePage();
        this.cdr.detectChanges();
      },
      error: err => console.error('Error loading donors', err),
    });
  }
  onPageChange(event: any) {
    this.first = event.first;
    this.rows = event.rows;
    this.updatePage();
  }

  private updatePage() {
    this.pagedGifts = this.allGifts.slice(this.first, this.first + this.rows);
  }

  // === Dialogs ===
  openAddGiftDialog() {
    this.errorMessage = '';
    this.newGift = { Name: '', Description: '', CategoryId: 1, TicketPrice: 10, Image: '', DonorId: 1 };
    this.displayAddDialog = true;
  }
  openEditGiftDialog(gift: GiftModel) {
    this.selectedGiftForEdit = JSON.parse(JSON.stringify(gift));

    const categoryObj = this.allCategories.find(c => c.name === gift.category);
    this.selectedGiftForEdit.CategoryId = categoryObj ? categoryObj.id : null;

    const donorObj = this.allDonors.find(d => (d.firstName + ' ' + d.lastName) === gift.donor);
    this.selectedGiftForEdit.DonorId = donorObj ? donorObj.id : null;

    this.selectedGiftForEdit.Image = gift.image;
    this.displayEditDialog = true;
    this.cdr.detectChanges();
  }
  onUpload(event: any, isEdit: boolean = false) {
    const file = event.files?.[0];
    if (!file) return;

    if (isEdit) {
      this.selectedGiftForEdit.Image = file.name;
    } else {
      this.newGift.Image = file.name;
    }
  }
  saveNewGift() {
    if (!this.validateGift(this.newGift)) return;

    this.isLoading = true;
    this.giftService.addGift(this.newGift).subscribe({
      next: () => {
        this.displayAddDialog = false;
        this.isLoading = false;
        this.loadGifts();
      },
      error: () => {
        this.errorMessage = 'אירעה שגיאה בשמירת המתנה.';
        this.isLoading = false;
        this.cdr.detectChanges();
      },
    });
  }

  updateGift() {
    const g = this.selectedGiftForEdit;
    if (!this.validateGift(g)) return;

    this.giftService.updateGift(g.id, g).subscribe({
      next: res => {
        if (res === null) {
          this.errorMessage = 'לא ניתן לעדכן את המתנה (נמחקה או כבר נרכשה)';
          return;
        }
        this.displayEditDialog = false;
        this.loadGifts();
      },
      error: err => {
        this.errorMessage =
          err.status === 404
            ? 'לא ניתן לעדכן את המתנה (המתנה לא נמצאה או נמחקה)'
            : 'אירעה שגיאה בשמירת המתנה.';
        this.cdr.detectChanges();
      },
    });
  }
  private validateGift(g: any): boolean {
    if (!g.Name || !g.Description || !g.TicketPrice || !g.DonorId || !g.CategoryId || !g.Image) {
      this.errorMessage = 'נא למלא את כל שדות החובה לפני השמירה';
      return false;
    }
    this.errorMessage = '';
    return true;
  }

  // === Delete Gift ===
  deleteGift(id: number) {
    if (!confirm('האם את בטוחה שברצונך למחוק את המתנה הזו?')) return;

    this.giftService.deleteGift(id).subscribe({
      next: () => this.loadGifts(),
      error: err => {
        console.error('שגיאה במחיקה:', err);
        this.errorMessage = 'לא ניתן למחוק את המתנה (ייתכן שהיא כבר נרכשה)';
      },
    });
  }
  addToCart(giftId: number) {
    if (!this.cartUserId) {
      this.addToGuestCart(giftId);
      return;
    }

    this.cartService.AddGiftToCart({ userId: this.cartUserId, giftId }).subscribe({
      next: () => {},
      error: () => {
        this.errorMessage = 'לא ניתן להוסיף את המתנה לסל (ייתכן שכבר נרכשה)';
      },
    });
  }
  addToGuestCart(giftId: number) {
    const cart = JSON.parse(localStorage.getItem('guestCart') || '[]');
    const existingItem = cart.find((item: any) => item.giftId === giftId);

    if (existingItem) existingItem.quantity += 1;
    else cart.push({ giftId, quantity: 1 });

    localStorage.setItem('guestCart', JSON.stringify(cart));
  }

  raffleGift(giftId: number) {
    this.isLoading = true;
    this.giftService.ruffleGift(giftId).subscribe({
      next: () => this.loadGifts(),
      error: err => {
        console.error('שגיאה בהגרלה', err);
        this.isLoading = false;
      },
    });
  }
  sortByName(event: Event) {
    const value = (event.target as HTMLInputElement).value.trim();
    if (!value) return this.loadGifts();

    this.giftService.sortByName(value).subscribe(data => {
      this.allGifts = data;
      this.first = 0;
      this.updatePage();
      this.cdr.detectChanges();
    });
  }

  sortByDonorName(event: Event) {
    const value = (event.target as HTMLInputElement).value.trim();
    if (!value) return this.loadGifts();

    this.giftService.sortByDonorName(value).subscribe(data => {
      this.allGifts = data;
      this.first = 0;
      this.updatePage();
      this.cdr.detectChanges();
    });
  }
  orderByCategory(categoryId: number) {
    if (!categoryId || categoryId === 0) return this.loadGifts();

    this.giftService.orderByCategory(categoryId).subscribe(data => {
      this.allGifts = data;
      this.first = 0;
      this.updatePage();
      this.cdr.detectChanges();
    });
  }
  orderByPrice() {
    this.giftService.orderByPrice().subscribe(data => {
      this.allGifts = data;
      this.first = 0;
      this.updatePage();
      this.cdr.detectChanges();
    });
  }

  sortByBuyers() {
    this.salesService.getGiftsByQuantityDesc().subscribe(data => {
      this.giftsWithBuyers = data;
    });
  }
  showBuyersDialog(giftId: number) {
    const gift = this.allGifts.find(g => g.id === giftId);
    if (!gift) return;

    this.selectedGiftId = giftId;
    this.selectedGiftName = gift.name;
    this.displayBuyersDialog = true;
  }

  details(id: number) {
    this.router.navigate(['/gift', id]);
  }

}
<div class="admin-dashboard">

  <!-- Sidebar -->
  <div class="sidebar">
    <h3>ניהול מתנות</h3>
    <ul>
      <li class="active">מתנות</li>
      <li>רוכשים</li>
      <li>תורמים</li>
      <li>דוחות</li>
      <li>הגדרות</li>
    </ul>
  </div>

  <!-- Main Content -->
  <div class="main-content">

    <!-- Header עם כפתור הוספה -->
    <div class="header-section flex align-center justify-between">
      <h2>רשימת מתנות זהובה</h2>
      <button *ngIf="isAdmin" class="add-gift-btn" (click)="openAddGiftDialog()">
        <i class="pi pi-plus"></i> הוספת מוצר
      </button>
    </div>

    <!-- כרטיסי סטטיסטיקה -->
    <div class="stats-cards grid">
      <div class="card">
        <h4>סה"כ מתנות</h4>
        <span>{{ allGifts.length }}</span>
      </div>
      <div class="card">
        <h4>סה"כ רוכשים</h4>
        <span>{{ giftsWithBuyers.length }}</span>
      </div>
      <div class="card">
        <h4>סה"כ תורמים</h4>
        <span>{{ allDonors.length }}</span>
      </div>
    </div>

    <!-- Search & Filters -->
    <div class="filters flex gap-2">
      <div class="p-inputgroup">
        <span class="p-inputgroup-addon">
          <i class="pi pi-search"></i>
        </span>
        <input pInputText type="text" placeholder="חיפוש מתנה לפי שם..." (input)="sortByName($event)" />
      </div>
      <div class="p-inputgroup">
        <span class="p-inputgroup-addon">
          <i class="pi pi-user"></i>
        </span>
        <input pInputText type="text" placeholder="חיפוש לפי שם תורם..." (input)="sortByDonorName($event)" />
      </div>
      <button pButton label="מיין לפי מחיר" (click)="orderByPrice()"></button>
      <button pButton label="מיין לפי קונים" (click)="sortByBuyers()"></button>
      <p-dropdown [options]="allCategories" optionLabel="name" placeholder="סנן לפי קטגוריה"
          (onChange)="orderByCategory($event.value?.id)">
      </p-dropdown>
    </div>

    <!-- Grid מתנות -->
    <div class="gift-grid">
      <div *ngFor="let gift of pagedGifts" class="gift-card">

        <div class="image-wrapper">
          <img (click)="details(gift.id)" [src]="'assets/images/gifts/' + gift.image" [alt]="gift.name">
          <div class="category-badge">{{ gift.category }}</div>

          <div class="admin-actions" *ngIf="isAdmin">
            <button class="admin-edit-btn" (click)="openEditGiftDialog(gift); $event.stopPropagation()">
              <i class="pi pi-pencil"></i>
            </button>
            <button class="admin-delete-btn" (click)="deleteGift(gift.id); $event.stopPropagation()">
              <i class="pi pi-trash"></i>
            </button>
            <button class="admin-buyers-btn" (click)="showBuyersDialog(gift.id); $event.stopPropagation()">
              רוכשים
            </button>
          </div>
        </div>

        <div class="card-content">
          <h3>{{ gift.name }}</h3>
          <p>תורם: {{ gift.donor }}</p>
          <p>זוכה: {{ gift.winnerName || 'לא הוגרלה' }}</p>
          <span class="price">{{ gift.ticketPrice | currency:'ILS':'symbol':'1.0-0' }}</span>

          <div class="card-buttons">
            <button class="add-to-cart-btn" (click)="raffleGift(gift.id); $event.stopPropagation()">
              הגרל <i class="pi pi-shopping-cart"></i>
            </button>
            <button class="add-to-cart-btn" (click)="addToCart(gift.id); $event.stopPropagation()">
              הוספה לסל <i class="pi pi-shopping-cart"></i>
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- Pagination -->
    <div class="paginator-wrapper">
      <p-paginator (onPageChange)="onPageChange($event)" [first]="first" [rows]="rows"
          [totalRecords]="allGifts.length" [rowsPerPageOptions]="[6,12,24]"></p-paginator>
    </div>

  </div>
</div>
